import{_ as i,c as a,a as n,o as e}from"./app-CEcM0piI.js";const l={};function p(d,s){return e(),a("div",null,s[0]||(s[0]=[n(`<p>对SpringBoot项目打包（执行Maven构建指令package）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mvn package</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>运行项目 （执行启动指令）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>java -jar 包名.jar</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>jar支持命令行启动需要依赖maven插件支持，请确认打包时是否具有SpringBoot对应的maven插件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;build&gt;</span></span>
<span class="line"><span>	&lt;plugins&gt;</span></span>
<span class="line"><span>		&lt;plugin&gt;</span></span>
<span class="line"><span>			&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;</span></span>
<span class="line"><span>			&lt;artifactId&gt;spring-boot-maven-plugin&lt;/artifactId&gt;</span></span>
<span class="line"><span>		&lt;/plugin&gt;</span></span>
<span class="line"><span>	&lt;/plugins&gt;</span></span>
<span class="line"><span>&lt;/build&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果打包时不使用springboot插件获得的包是不能直接运行的, 使用springboot打包插件打包里面的文件包括依赖的包,spring启动所需的东西以及指明启动类. 而不使用打包插件打包出来的不包含这些东西因此无法直接运行</p><h1 id="临时属性" tabindex="-1"><a class="header-anchor" href="#临时属性"><span>临时属性</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>java -jar springboot.jar --server.port=80</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>对于properites中的属性都可以在执行运行命令时进行更改的 携带多个属性启动SpringBoot，属性间使用空格分隔</p><h2 id="指定配置文件" tabindex="-1"><a class="header-anchor" href="#指定配置文件"><span>指定配置文件</span></a></h2><p>配置文件名都是property命名的,也可以使用自己命名的文件做配置文件,前提是文件类型能够被识别</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>--spring.config.name=config.yml</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果不再同一目录下需要使用location</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>--spring.confih.location=classpath:/config.yml</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果有多个相同属性的命令行参数配置,后面的配置覆盖前面的</p><h2 id="多环境" tabindex="-1"><a class="header-anchor" href="#多环境"><span>多环境</span></a></h2><h3 id="在一个文件中配置多个环境" tabindex="-1"><a class="header-anchor" href="#在一个文件中配置多个环境"><span>在一个文件中配置多个环境</span></a></h3><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#应用环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:</span></span>
<span class="line"><span>		active:pro</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#设置环境</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>#生产环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:pro</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:80</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>#开发环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles: dev</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:81</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>#测试环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles: test</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:82</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>不同的环境使用---隔开,使用<code>spring.profiles</code>给环境命名,<code>spring.profiles.active:</code>设置使用的环境</p><p>最上面没有---的区域为公共区域,在公共区域写的配置所有环境都会加载</p><p>如果要指定默认的环境还可以直接在环境中指定</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>---</span></span>
<span class="line"><span>#设置环境</span></span>
<span class="line"><span>#生产环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles: pro</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:80</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>#开发环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:dev</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:81</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>#测试环境</span></span>
<span class="line"><span>spring:</span></span>
<span class="line"><span>	config:</span></span>
<span class="line"><span>		activate:</span></span>
<span class="line"><span>			on-profile:test</span></span>
<span class="line"><span>server:</span></span>
<span class="line"><span>	port:82</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h3 id="在多个独立的文件配置多个环境" tabindex="-1"><a class="header-anchor" href="#在多个独立的文件配置多个环境"><span>在多个独立的文件配置多个环境</span></a></h3><p>也可以将多个环境配置文件分开,但要放在同一目录下,在主配置文件中指明默认配置文件</p><div class="language-application.yml line-numbers-mode" data-highlighter="shiki" data-ext="application.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:</span></span>
<span class="line"><span>		active:dev</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-application-dev.yml line-numbers-mode" data-highlighter="shiki" data-ext="application-dev.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>server:</span></span>
<span class="line"><span>	port: 8080</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-application-test.yml line-numbers-mode" data-highlighter="shiki" data-ext="application-test.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>server:</span></span>
<span class="line"><span>	port: 8081</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="引入其他的配置文件" tabindex="-1"><a class="header-anchor" href="#引入其他的配置文件"><span>引入其他的配置文件</span></a></h4><p>可以使用include属性引入其他的配置文件,其他的配置文件名称必须是以application-开头 如application-devMVC,引入时可直接写为devMVC</p><div class="language-application.yml line-numbers-mode" data-highlighter="shiki" data-ext="application.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:</span></span>
<span class="line"><span>		active: dev</span></span>
<span class="line"><span>		include: devMVC,devDB</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="分组管理" tabindex="-1"><a class="header-anchor" href="#分组管理"><span>分组管理</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:</span></span>
<span class="line"><span>		active:dev</span></span>
<span class="line"><span>		group:</span></span>
<span class="line"><span>			&quot;dev&quot;:devDB,devMVC</span></span>
<span class="line"><span>			&quot;pro&quot;:proDB,proMVC</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>分组后active表示的就是生效的组了</p><h2 id="读取maven环境" tabindex="-1"><a class="header-anchor" href="#读取maven环境"><span>读取maven环境</span></a></h2><p>在maven中也可以配置多环境</p><div class="language-pom.xml line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="pom.xml" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;！--设置多环境--&gt;</span></span>
<span class="line"><span>&lt;profiles&gt;</span></span>
<span class="line"><span>	&lt;profile&gt;</span></span>
<span class="line"><span>		&lt;！--环境id--&gt;</span></span>
<span class="line"><span>		&lt;id&gt;env_dev&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;properties&gt;</span></span>
<span class="line"><span>			&lt;！--设置默认的环境--&gt;</span></span>
<span class="line"><span>			&lt;profile.active&gt;dev&lt;/profile.active&gt;</span></span>
<span class="line"><span>		&lt;/properties&gt;</span></span>
<span class="line"><span>		&lt;activation&gt;</span></span>
<span class="line"><span>			&lt;activeByDefault&gt;true&lt;/activeByDefault&gt;</span></span>
<span class="line"><span>		&lt;/activation&gt;</span></span>
<span class="line"><span>	&lt;/profile&gt;</span></span>
<span class="line"><span>	&lt;profile&gt;</span></span>
<span class="line"><span>		&lt;id&gt;env_pro&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;properties&gt;</span></span>
<span class="line"><span>			&lt;profile.active&gt;pro&lt;/profile.active&gt;</span></span>
<span class="line"><span>		&lt;/properties&gt;</span></span>
<span class="line"><span>	&lt;/profile&gt;</span></span>
<span class="line"><span>&lt;/profiles&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>在spring 的配置文件中就可以使用@@符取默认环境了</p><div class="language-application.yml line-numbers-mode" data-highlighter="shiki" data-ext="application.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>spring:</span></span>
<span class="line"><span>	profiles:</span></span>
<span class="line"><span>		active:@.profile.active.@</span></span>
<span class="line"><span>		group:</span></span>
<span class="line"><span>			&quot;dev&quot;:devDB,devMVC</span></span>
<span class="line"><span>			&quot;pro&quot;:devDB,proMVC</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>[!warning] Title 基于SpringBoot读取Maven配置属性的前提下，如果在Idea下测试工程时pom.xml每次更新需要手动compile方可生效</p></blockquote><h1 id="日志" tabindex="-1"><a class="header-anchor" href="#日志"><span>日志</span></a></h1><p>日志有六个级别,后果从下到上依次是:</p><ul><li>trace : 堆栈信息,由于级别太低一般不使用</li><li>debug : 给程序员看的</li><li>info : 信息</li><li>warn : 警告</li><li>error : 错误</li><li>fatal : 灾难,这种情况描述的是类似于系统崩溃的情况,但系统崩溃了日志也不太可能运行所以这个信息在Slf4j中并不提供而是和error合并了</li></ul><p>控制台默认情况下只显示info及以上的信息,如果要显示其他级别的日志可以在配置文件中更改</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>debug: true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>这是配置全局路径都显示debug级别的信息</p><p>可以只显示当前项目根路径下显示debug信息</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>	level:</span></span>
<span class="line"><span>		root: debug</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="单独给一个包设置级别" tabindex="-1"><a class="header-anchor" href="#单独给一个包设置级别"><span>单独给一个包设置级别</span></a></h3><p>也可以单独设置某个包的日志级别</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>	level:</span></span>
<span class="line"><span>		root: debug</span></span>
<span class="line"><span>		com.itheima.controller: debug</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="分组设置级别" tabindex="-1"><a class="header-anchor" href="#分组设置级别"><span>分组设置级别</span></a></h3><p>也可以分组设置级别</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>	#设置分组</span></span>
<span class="line"><span>	group:</span></span>
<span class="line"><span>		ebank:com.itheima.controller,com.itheima.service,com.itheima.dao</span></span>
<span class="line"><span>		iservice: com.alibaba</span></span>
<span class="line"><span>	level:</span></span>
<span class="line"><span>		root:info</span></span>
<span class="line"><span>		#设置某个包的日志级别</span></span>
<span class="line"><span>		com.itheima.controller:debug</span></span>
<span class="line"><span>		#设置分组，对某个组设置日志级别</span></span>
<span class="line"><span>		ebank:warn</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="日志格式输出规则" tabindex="-1"><a class="header-anchor" href="#日志格式输出规则"><span>日志格式输出规则</span></a></h2><p>![[Pasted image 20241028195426.png]]</p><ul><li>PID：进程ID，用于表明当前操作所处的进程，当多服务同时记录日志时，该值可用于协助程序员调试程序</li><li>所属类/接口名：当前显示信息为SpringBoot重写后的信息，名称过长时，简化包名书写为首字母，甚至直接删除</li></ul><p>设置日志输出格式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>	pattern:</span></span>
<span class="line"><span>		console:&quot;%d-%m%n&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>%d : 日期</li><li>%m : 消息</li><li>%n : 换行</li><li>%t : pid 在百分号之间加上clr表示开启颜色(前提是控制台支持颜色)</li></ul><p>示例 : 拥有springboot同款日志</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>  pattern:</span></span>
<span class="line"><span>    console: &quot;%d %clr(%5p) --- [%16t] %clr(%-40.40c){cyan} : %m %n&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="日志文件配置" tabindex="-1"><a class="header-anchor" href="#日志文件配置"><span>日志文件配置</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>logging:</span></span>
<span class="line"><span>	file:</span></span>
<span class="line"><span>		name: server.log</span></span>
<span class="line"><span>	logback:</span></span>
<span class="line"><span>		rollingpolicy:</span></span>
<span class="line"><span>			max-file-size: 3KB</span></span>
<span class="line"><span>			file-name-pattern: server.%d{yyyy-MM-dd}.%i.log</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="热部署" tabindex="-1"><a class="header-anchor" href="#热部署"><span>热部署</span></a></h1><p>通过spring的依赖插件实现热部署</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;dependency&gt;</span></span>
<span class="line"><span>	&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;</span></span>
<span class="line"><span>	&lt;artifactId&gt;spring-boot-devtools&lt;/artifactId&gt;</span></span>
<span class="line"><span>&lt;/dependency&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>它会检测代码更改的地方如果有更改就自动重启tomcat实现热部署 热部署需要先运行编译命令</p><ul><li>重启（Restart）：自定义开发代码，包含类、页面、配置文件等，加载位置restart类加载器</li><li>重载（ReLoad）：jar包，加载位置base类加载器 运行包含重启和重载,热部署只包含重启</li></ul><h3 id="热部署的配置范围" tabindex="-1"><a class="header-anchor" href="#热部署的配置范围"><span>热部署的配置范围</span></a></h3><p>默认不触发重启的目录列表:</p><ul><li>/META-INF/maven</li><li>/META-INF/resources</li><li>/resources</li><li>/static</li><li>/public</li><li>/templates</li></ul><h4 id="配置热部署排除的文件夹" tabindex="-1"><a class="header-anchor" href="#配置热部署排除的文件夹"><span>配置热部署排除的文件夹</span></a></h4><div class="language-application.yml line-numbers-mode" data-highlighter="shiki" data-ext="application.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>devtools:</span></span>
<span class="line"><span>	restart:</span></span>
<span class="line"><span>		exclude:static/**,public/**,config/application.yml</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="关闭热部署" tabindex="-1"><a class="header-anchor" href="#关闭热部署"><span>关闭热部署</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>devtools:</span></span>
<span class="line"><span>	restart:</span></span>
<span class="line"><span>		enabled: false</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="configurationproperties" tabindex="-1"><a class="header-anchor" href="#configurationproperties"><span>@ConfigurationProperties</span></a></h1><p>宽松绑定 对于使用这个注解的类,<strong>类成员</strong>支持多种驼峰命名法的绑定方式</p><ul><li>ipAddress</li><li>ipaddress</li><li>IpAddress</li><li>ip_address</li><li>ip-address 但绑定前缀必须是全小写或烤肉串模式</li><li>ipadress</li><li>ip-address</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@ConfigurationProperties(prefix=&quot;datasource&quot;)//必须是全小写或烤肉串模式</span></span>
<span class="line"><span>public class Config{</span></span>
<span class="line"><span>	String ipaddress;</span></span>
<span class="line"><span>	String userName;</span></span>
<span class="line"><span>	String user-name;</span></span>
<span class="line"><span>	//类名可以是常用的驼峰命名法模式</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>@Value注解不支持宽松绑定</p><h1 id="测试" tabindex="-1"><a class="header-anchor" href="#测试"><span>测试</span></a></h1><h3 id="在测试环境中临时添加一个配置" tabindex="-1"><a class="header-anchor" href="#在测试环境中临时添加一个配置"><span>在测试环境中临时添加一个配置</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootTest(properties={&quot;test.prop=testValue1&quot;})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果在配置中有相同键的配置那么临时添加的配置会覆盖原配置中的值</p><p>使用args属性临时添加环境参数,环境参数优先级大雨临时配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootTest(properties={&quot;test.prop=testValue1&quot;},args={&quot;--test.prop=testValue2&quot;})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="在测试环境中添加一个bean对象" tabindex="-1"><a class="header-anchor" href="#在测试环境中添加一个bean对象"><span>在测试环境中添加一个bean对象</span></a></h3><p>使用Import注解</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootTest</span></span>
<span class="line"><span>@Import({MsgConfig.class})</span></span>
<span class="line"><span>public class ConfigurationTest{</span></span>
<span class="line"><span>	@Autowired</span></span>
<span class="line"><span>	private String msg;</span></span>
<span class="line"><span>	@Test</span></span>
<span class="line"><span>	void testconfiguration(){}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>由于测试包在运行时是模拟了 一个spring的运行环境,所以使用Import注解也是可以在测试类中添加一个bean对象的</p><h3 id="环境模拟测试" tabindex="-1"><a class="header-anchor" href="#环境模拟测试"><span>环境模拟测试</span></a></h3><p>从一个web环境上模拟一个随机端口</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootTest(webEnvironment=SprinotTest.WebEnvironment.RANDOM_PORT)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="虚拟调用" tabindex="-1"><a class="header-anchor" href="#虚拟调用"><span>虚拟调用</span></a></h2><p>如果在测试类中要测试web请求可以使用虚拟调用 需要在在测试类上方写上@AutoConfigureMockMvc注解 接着使用自动注入或者直接使用形参获取MockMvc对象后就可以在测试类中进行虚拟请求调用了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@AutoConfigureMockMvc</span></span>
<span class="line"><span>public class WebTest{</span></span>
<span class="line"><span>	@Test</span></span>
<span class="line"><span>	void testWeb(@Autowired MockMvc mvc)throwsException{</span></span>
<span class="line"><span>	//http://localhost:8080/books</span></span>
<span class="line"><span>		//创建虚拟请求，当前访问/books</span></span>
<span class="line"><span>		MockHttpServletRequestBuilder builder = MockMvcRequestBuilders.get(urlTemplate:&quot;/books&quot;);</span></span>
<span class="line"><span>		//执行对应的请求</span></span>
<span class="line"><span>		mvc.perform(builder);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="虚拟请求状态匹配" tabindex="-1"><a class="header-anchor" href="#虚拟请求状态匹配"><span>虚拟请求状态匹配</span></a></h4><p>查看返回的状态码是否与预期相符 andExpect可以判断两个结果是否匹配,如不匹配就报错,相比于断言它能提供更详细的信息</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public void testSataus(@Autowired MockMvc mvc）throws Exception{</span></span>
<span class="line"><span>	MockHttpServletRequestBuilder builder = MockMvcRequestBuilders.get(&quot;/books&quot;);</span></span>
<span class="line"><span>	ResultActions action = mvc.perform(builder);</span></span>
<span class="line"><span>	//匹配执行状态（是否预期值）</span></span>
<span class="line"><span>	//定义执行状态匹配器</span></span>
<span class="line"><span>	StatusResultMatchers status =MockMvcResultMatchers.status();</span></span>
<span class="line"><span>	//定义预期执行状态</span></span>
<span class="line"><span>	ResultMatcher ok = status.isok();</span></span>
<span class="line"><span>	//使用本次真实执行结果与预期结果进行比对</span></span>
<span class="line"><span>	action.andExpect(ok);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="虚拟请求体匹配" tabindex="-1"><a class="header-anchor" href="#虚拟请求体匹配"><span>虚拟请求体匹配</span></a></h4><p>判断请求体中有没有预期的内容</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ContentResultMatchers content =MockMvcResultMatchers.content();</span></span>
<span class="line"><span>//定义预期执行结果</span></span>
<span class="line"><span>RsultMatcher result = content().string(&quot;springboot&quot;);</span></span>
<span class="line"><span>1/使用本次真实执行结果与预期结果进行比对</span></span>
<span class="line"><span>action.andExpect(result);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="json的结果" tabindex="-1"><a class="header-anchor" href="#json的结果"><span>json的结果</span></a></h5><p>不同的类型只需要将类型名的函数改变即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>RsultMatcher result = content().json(&quot;{\\&quot;id\\&quot;:1,\\&quot;name\\&quot;:\\&quot;springboot\\&quot;}&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>要判断哪个属性只需要根据请求获取该属性所在的区域再进行判断即可,如type在请求头中因此需要获取请求头的对象</strong></p><h3 id="数据库事务" tabindex="-1"><a class="header-anchor" href="#数据库事务"><span>数据库事务</span></a></h3><p>在测试类中测试数据库的话会存入数据,可以将事务开启并关闭提交,这样数据就不会被保存到数据库中了</p><p>在测试类上加上@Transactional注解,就不会提交数据了 springboot检测到这个注解在测试类才会不提交只对测试类有效</p><p>也可以再加上@Rollback直接将参数设置为bool值控制是否提交</p><h2 id="随机数据" tabindex="-1"><a class="header-anchor" href="#随机数据"><span>随机数据</span></a></h2><p>可以在配置中生成随机数据用于测试</p><div class="language-application.yml line-numbers-mode" data-highlighter="shiki" data-ext="application.yml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>testcase:</span></span>
<span class="line"><span>	book:</span></span>
<span class="line"><span>		id:$\${random.int}</span></span>
<span class="line"><span>		name:\${random.value}</span></span>
<span class="line"><span>		uuid:\${random.uuid}</span></span>
<span class="line"><span>		publishTime:\${random.long}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,114)]))}const r=i(l,[["render",p]]),c=JSON.parse('{"path":"/back/springboot/8/","title":"8 运维","lang":"zh-CN","frontmatter":{"title":"8 运维","createTime":"2025/06/22 09:48:44","permalink":"/back/springboot/8/"},"readingTime":{"minutes":7.54,"words":2262},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Spring Boot/8 运维.md","headers":[]}');export{r as comp,c as data};
